export interface V1SupplyOrderContentUpdateValidationResponse {
    /**
     * Ошибки:  - `UNSPECIFIED` — не определено.  - `UNKNOWN` — неизвестный тип.  - `INCORRECT_SUPPLY_STATE` — нельзя изменить поставку в этом статусе.  - `DEADLINE` — нельзя изменить поставку за час до таймслота.  - `UTD_IS_UPLOADED` — документы в системе ЭДО не удалены. Аннулируйте документы в системе ЭДО. Когда отредактируете состав, сформируйте и подпишите новые документы.  - `STORAGE_WAREHOUSE_IS_NOT_WMS` — нельзя редактировать товарный состав.  - `CONTRACT_IS_NOT_VALID_FOR_HANDLING_ORDERS` — в этом личном кабинете нельзя изменить поставку.  - `SUPPLY_IS_VIRTUAL` — нельзя редактировать виртуальную поставку.  - `SUPPLY_DOES_NOT_BELONG_TO_COMPANY` — заявка на поставку не принадлежит вашему кабинету.  - `ASSORTMENT_REJECTION_REASON_CORRUPTED_ASSORTMENT` — не получилось добавить товар в заявку. Попробуйте ещё раз.  - `ASSORTMENT_REJECTION_REASON_STORAGE_BELARUS_SKU_HAS_NO_ANY_FEACN`, `ASSORTMENT_REJECTION_REASON_STORAGE_BELARUS_SKU_HAS_NO_SELLER_FEACN` — у товара нет кода ТН ВЭД ЕАЭС.   - `ASSORTMENT_REJECTION_REASON_TRACEABLE_SKU_HAS_NO_GTIN_BARCODE` — у товара нет штрихкода GTIN.  - `ASSORTMENT_REJECTION_REASON_TRACEABLE_SKU_HAS_NO_MEASUREMENT_UNIT_QUANTITY` — не указано количество товара в унифицированных единицах измерения. 
     */
    'editing_errors'?: Array<SupplyOrderContentUpdateValidationResponseEditingErrorEnum>;
    'validated_assortment'?: SupplyOrderContentUpdateValidationResponseValidatedAssortment;
}
